# loaders/raman_loader.pyimport tkinter as tkfrom tkinter import filedialogimport osimport matplotlib.pyplot as pltimport spcimport ramanspyfrom collections import defaultdictimport globdef select_directory():    root = tk.Tk()    root.withdraw()  # Hide the main window    root.attributes('-topmost', True)  # Bring dialog to the front    directory = filedialog.askdirectory(title="Select Raman Spectra Directory")    root.destroy()    return directorydef select_file():    root = tk.Tk()    root.withdraw()  # Hide the main window    root.attributes('-topmost', True)  # Bring dialog to the front    file_path = filedialog.askopenfilename(title="Select GCMS Data File", filetypes=[("Excel files", "*.xlsx")])    root.destroy()    return file_pathdef load_raman(directory, spectra_dir):    sample_spectra = {}    shifts = None    colors = plt.cm.tab10.colors    sample_group_colors = {}    spc_files = glob.glob(os.path.join(directory, "**", "*.spc"), recursive=True)    for raman_path in spc_files:            filename = os.path.basename(raman_path)            sample_name = filename.split('_')[0]            raw = spc.File(raman_path)            if len(raw.sub) > 0:                shifts = raw.x            spectral_data = raw.sub[0].y            spectrum = ramanspy.Spectrum(spectral_data, shifts)            # Save individual plot            plt.figure(figsize=(8, 5))            plt.plot(spectrum.spectral_axis, spectrum.spectral_data, label=sample_name, color="blue")            plt.title(f"Raw Spectrum: {sample_name}")            plt.xlabel("Raman Shift (cm⁻¹)")            plt.ylabel("Intensity")            plt.savefig(os.path.join(spectra_dir, f"{sample_name}_Raw.png"), dpi=300, bbox_inches="tight")            plt.close()            # Store in dictionary            if sample_name not in sample_spectra:                sample_spectra[sample_name] = []            sample_spectra[sample_name].append(spectrum)    # === Build group dictionary from sample names    group_dict = defaultdict(list)    for sample_name in sample_spectra.keys():        group_id = sample_name.split("-")[0]        group_dict[group_id].append(sample_name)    # === Overlay Plot ===    plotted_groups = set()    plt.figure(figsize=(8, 5))    for group_idx, (group_id, sample_names) in enumerate(group_dict.items()):        if group_id not in sample_group_colors:            sample_group_colors[group_id] = colors[group_idx % len(colors)]        for sample_name in sample_names:            for spectrum in sample_spectra[sample_name]:                label = group_id if group_id not in plotted_groups else None                plt.plot(                    spectrum.spectral_axis,                    spectrum.spectral_data,                    label=label,                    color=sample_group_colors[group_id]                )        plotted_groups.add(group_id)    plt.title("Overlay of Raw Spectra")    plt.xlabel("Raman Shift (cm⁻¹)")    plt.ylabel("Intensity")    #plt.legend(loc="best", ncol=2, fontsize="small")    plt.savefig(os.path.join(spectra_dir, "Overlay_Raw.png"), dpi=300, bbox_inches="tight")    plt.close()    return sample_spectra, shifts, dict(group_dict)